callGraph.callee:
interviews
    .filter(interview => {
      if (!interview.interviewTime) return false;
      const d = dayjs(interview.interviewTime);
      return d.isValid();
    })
    .map

([
                        {
                          value: 'text' as InterviewMode,
                          label: '文字面试',
                          icon: FileText,
                          desc: '推荐：更稳定，更适合系统化练习',
                          recommended: true,
                        },
                        {
                          value: 'voice' as InterviewMode,
                          label: '语音面试',
                          icon: Mic,
                          desc: '实时语音对话，偏临场模拟',
                          recommended: false,
                        },
                      ]).map

(() => {
                            const CustomIcon = getSkillIcon(CUSTOM_SKILL_ID);
                            return CustomIcon
                              ? <CustomIcon className={`w-5 h-5 ${config.isCustomSkill ? 'text-primary-600 dark:text-primary-400' : 'text-slate-500 dark:text-slate-400'}`} />
                              : <span className="text-base">✨</span>;
                          })
